INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('一丛花', '一叢花', '一丛花令', '一丛花，词牌名。亦称《一丛花令》。双调，共七十八字。前后阕相同，各七句，三十九字，押四平韵。', '平平平仄仄平平，平仄仄平平。平平仄仄平平仄，仄平仄、仄仄平平。平仄仄平，平平仄仄，平仄仄平平。
平平平仄仄平平，平仄仄平平。平平仄仄平平仄，仄平仄、平仄平平。平仄仄平，平平仄仄，平仄仄平平。', 2, 78, '**苏轼**

今年春浅腊侵年。冰雪破春妍。东风有信无人见。露微意、柳际花边。寒夜纵长。孤衾易暖。钟鼓渐清圆。
朝来初日半含山。楼阁淡疏烟。游人便作寻芳计。小桃杏、应已争先。衰病少情。疏慵自放。惟爱日高眠。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('一斛珠', '一斛珠', '醉落魄,怨春风,醉落拓', '一斛珠，词牌名。双调，五十七字。前后阕各五句、四仄韵。', '仄平平仄，平平平仄平平仄。仄平平仄平平仄。仄仄平平、仄仄平平仄。平仄仄平平仄仄，平平仄仄平平仄。仄平平仄平平仄。仄仄平平、仄仄平平仄。', 2, 57, '**李煜**

一斛珠·晚妆初过晚妆初过。沈檀轻注些儿个。向人微露丁香颗。一曲清歌、暂引樱桃破。罗袖裛残殷色可。杯深旋被香醪涴。绣床斜凭娇无那。烂嚼红茸、笑向檀郎唾。');
