INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('临江仙', '臨江仙', NULL, '临江仙，词牌名。最初是咏水仙的，调见《花间集》，以后作一般词牌用。上下片各五句。

双调六十字，前后阕各三平韵，一韵到底。上下片各五句。', '仄仄平平平仄仄，平平仄仄平平。平平仄仄仄平平，平平平仄仄，仄仄仄平平。仄仄平平平仄仄，平平仄仄平平。平平仄仄仄平平，平平平仄仄，仄仄仄平平。', 2, 60, '**李清照**

庭院深深深几许，云窗雾阁常扃，柳梢梅萼渐分明，春归秣陵树，人老建康城。
感月吟风多少事，如今老去无成，谁怜憔悴更凋零，试灯无意思，踏雪没心情。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('乌夜啼', '烏夜啼', '乐府诗集,乌夜啼,圣无忧,锦堂春', '乌夜啼，词牌名，本为唐代教坊曲。双调四十七字，前后段各四句，两平韵。唐朝李白、白居易等人有同名诗作《乌夜啼》，但不是词。', '仄仄平平仄，平平仄仄平平。仄平仄仄平平仄，仄仄仄平平。仄仄仄平平仄，仄平仄仄平平。仄平仄仄平平仄，仄仄仄平平。', 2, 47, '**李煜**

昨夜风兼雨，帘帏飒飒秋声。烛残漏断频敧枕，起坐不能平。
世事漫随流水，算来一梦浮生。醉乡路稳宜频到，此外不堪行。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('何满子', '何滿子', NULL, '《何满子》，词牌名。双调，共计七十四字。正格单调为三十六字，又一体单调为三十七字，或双调七十四字。', '仄仄平平平仄，平平仄仄平平。仄仄平平平仄仄，平平仄仄平平。仄仄平平平仄，平平仄仄平平。
仄仄平平仄仄，平平仄仄平平。仄仄平平平仄仄，平平仄仄平平。仄仄平平平仄，平平仄仄平平。', 2, 74, '**苏轼**

见说岷峨凄怆，旋闻江汉澄清。但觉秋来归梦好，西南自有长城。东府三人最少，西山八国初平。
莫负花溪纵赏，何妨药市微行。试问当垆人在否，空教是处闻名。唱着子渊新曲，应须分外含情。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('八声甘州', '八聲甘州', '甘州,潇潇雨,宴瑶池', '八声甘州，词牌名。亦称《甘州》、《潇潇雨》、《宴瑶池》。此调取自唐教坊大曲《甘州》中的一段，全词上下阙共八韵，故称八声甘州。

双调九十七字，上下阕各九句，四平韵。', '仄平平仄仄仄平平，平平仄平平。仄平平仄仄，平平仄仄，仄仄平平。仄仄平平仄仄，仄仄仄平平。仄仄平平仄，仄仄平平。仄仄平平仄仄，仄平平平仄，平仄平平。仄平平平仄，平仄仄平平。仄平平、仄平平仄，仄仄平、平仄仄平平。平平仄、仄平平仄，仄仄平平。', 2, 97, '**柳永**

对潇潇暮雨洒江天，一番洗清秋。渐霜风凄紧，关河冷落，残照当楼。是处红衰翠减，苒苒物华休。惟有长江水，无语东流。
不忍登高临远，望故乡渺渺，归思难收。叹年来踪迹，何事苦淹留？想佳人、妆楼长望，误几回、天际识归舟。争知我、倚栏杆处，正恁凝愁！');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('六州歌头', '六州歌頭', NULL, '六州歌头，词牌名。

双调一百四十三字，前段十九句八平韵、八仄韵，后段二十句八平韵、十仄韵，同部平仄互押。亦有多变体。', '仄平仄仄，平仄仄平平（韵）。平平仄（韵），平仄仄（韵），仄平平（韵），仄平平（韵）。仄仄平平仄（韵），平平仄（韵），平平仄（韵），平仄仄（韵），平平仄（韵），仄平平（韵）。平仄仄平，平仄平平仄（韵），仄仄平平（韵）。仄平平仄仄，仄仄仄平平（韵），仄仄平平（韵），仄平平（韵）。
仄平平仄（韵），平平仄（韵），平仄仄（韵），仄平平（韵）。平仄仄（韵），平仄仄（韵），仄平平（韵），仄平平（韵）。仄仄平平仄（韵），平仄仄（韵），仄平平（韵）。平仄仄（韵），平平仄（韵），仄平平（韵）。仄仄平平，仄仄平平仄（韵），仄仄平平（韵）。仄平平平仄，仄仄仄平平（韵），仄仄平平（韵）。', 2, 143, '**张孝祥**

长淮望断，关塞莽然平。征尘暗，霜风劲，悄边声，黯销凝。追想当年事，殆天数，非人力，洙泗上，弦歌地，亦膻腥。隔水毡乡，落日牛羊下，区脱纵横。看名王宵猎，骑火一川明，笳鼓悲鸣，遣人惊。
念腰间箭，匣中剑，空埃蠹，竟何成！时易失，心徒壮，岁将零，渺神京。干羽方怀远，静烽燧，且休兵。冠盖使，纷驰骛，若为情。闻道中原遗老，常南望、翠葆霓旌。使行人到此，忠愤气填膺，有泪如倾。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('减字木兰花', '減字木蘭花', '梅苑,减兰,木兰香,高丽史·乐志,天下乐令', '减字木兰花，词牌名。亦称《减兰》等。双调四十四字，上下阕各两仄韵，两平韵。', '平平仄仄，平仄平平平仄仄。平仄平平，仄仄平平仄仄平。平平仄仄，平仄平平平仄仄。平仄平平，仄仄平平仄仄平。', 2, 44, '**欧阳修**

歌檀敛袂，缭绕雕梁尘暗起。柔润清圆，百琲明珠一线穿。
樱唇玉齿，天上仙音心下事。留住行云，满座迷魂酒半醺。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('凤凰台上忆吹箫', '鳳凰臺上憶吹簫', NULL, '凤凰台上忆吹箫，词牌名，以北宋词人晁补之作品为正体。', NULL, NULL, NULL, NULL);
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('凤池吟', '鳳池吟', NULL, '凤池吟，词牌名。此词于古代现只发现吴文英一例。', '仄仄平平。仄平平仄。仄仄仄仄平平。仄平平仄仄。平平仄仄。仄仄平平。
仄仄平平。仄平仄仄仄平平。平平仄仄。平平平仄。仄仄平平。
平平仄仄平仄。仄仄平仄仄。仄仄平平。仄仄平平仄。仄平平仄。仄仄平平。
仄仄平平。仄平平仄仄平平。平平仄。仄平平。仄仄平平。', NULL, NULL, '**吳文英**

萬丈巍台。碧罘罳外。袞袞野馬遊塵。舊文書幾閣。昏朝醉暮。覆雨翻雲。

忽變清明。紫垣敕使下星辰。經年事靜。公門如水。帝甸陽春。

長安父老相語。幾百年見此。獨駕冰輪。又鳳鳴黃幕。玉霄平溯。鵲錦新恩。

畫省中書。半紅梅子薦鹽新。歸來晚。待賡吟、殿閣南薰。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('十六字令', '十六字令', '苍梧谣,归字谣', '《十六字令》，词牌名，得名于周玉晨同名词，又名苍梧谣、归字谣。单调，十六字，四句、三平韵。', '平。仄仄平平仄仄平。平平仄，平仄仄平平。', 1, 16, '**蔡伸《苍梧谣》**

天。休使圆蟾照客眠。人何在，桂影自婵娟。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('南乡子', '南鄉子', NULL, '南乡子，词牌名，本为唐教坊曲。该词有单调、双调。单调者始于欧阳炯词，双调者始于冯延巳词。

单调二十七字，五句两平韵、三仄韵；双调多为五十六字，上下阕各四平韵。', '仄仄平平，仄平平仄仄平平。仄仄平平平仄仄，平仄。仄仄平平平仄仄。', 2, 27, '**欧阳炯**

画舸停桡。槿花篱外竹横桥。水上游人沙上女。回顾。笑指芭蕉林里住。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('南歌子', '南歌子', NULL, '《南歌子》，词牌，唐教坊曲名。

此词有单调、双调，
单调者始于温庭筠词，因词有“恨春宵”句，名《春宵曲》。张泌词本此添字，因词有“高卷水晶帘额”句，名《水晶帘》，又有“惊破碧窗残梦”句，名《碧窗梦》。郑子聃有“我爱沂阳好词”十首，更名《十爱词》。

双调者有平韵仄韵两体。
平韵者始自毛熙震词，周邦彦、杨无咎、僧挥五十四字体，无名氏五十三字体，俱本此添字。

仄韵者始《乐府雅词》，惟石孝友词最为谐婉，周邦彦词名《南柯子》，程垓词名《望秦川》，田不伐词有“帘风不动蝶交飞”句，名《风蝶令》。', '仄仄平平仄，平平仄仄平，平仄仄平平，仄平平仄仄，仄平平。', 2, 54, '**温庭筠**

手里金鹦鹉。胸前绣凤凰。偷眼暗形相。不如从嫁与。作鸳鸯');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('双双燕', '雙雙燕', NULL, '双双燕，词牌名，为史达祖首制，内容为吟咏双燕，故名。双调，上片九句，押五仄韵，四十八字；下片十句，押七仄韵，五十字，共九十八字。', '仄平仄仄，仄（去）平仄平平，仄平平仄（韵）。平平仄仄，仄仄仄平平仄（韵）。
平仄（去）平平仄仄（韵），仄仄仄、平平平仄（韵）。平平仄仄平平，仄仄平平平仄（韵）。
平仄（韵），平平仄仄（韵），仄（去）仄仄平平，仄平平仄（韵）。平平平仄，仄仄仄平平仄（韵）。
平仄平平仄仄（韵）。仄仄仄、平平平仄（韵）。平仄仄仄平平，仄仄仄平平仄（韵）。', 2, 48, '**史达祖**

过春社了，度帘幕中间，去年尘冷。差池欲往，试入旧巢相并。
还相雕梁藻井，又软语商量不定。飘然快拂花梢，翠尾分开红影。
芳径，芹泥雨润。爱贴地争飞，竞夸轻俊。红楼归晚，看足柳暗花瞑。
应自栖香正稳，便忘了、天涯芳信。愁损翠黛双蛾，日日画栏独凭。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('唐多令', '唐多令', NULL, '唐多令，词牌名，又名糖多令、南楼令、箜篌曲，自南宋中期兴起。本调六十字，通常一韵到底。', NULL, NULL, 60, '**刘过**

芦叶满汀洲，寒沙带浅流。二十年、重到南楼。柳下系船犹未稳，能几日，又中秋。
黄鹤断矶头，故人今在否？旧江山、总是新愁。欲买桂花同载酒，终不似，少年游。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('喝火令', '喝火令', NULL, '《喝火令》，词牌名。双调六十五字，前段五句三平韵，后段七句四平韵。此词后段第四、五、六句，前二字相同，为喝火令之特色。', '仄仄平平仄，平平仄仄平（对仗）。仄平平仄仄平平。平仄仄平平仄，平仄仄平平。仄仄平平仄，平平仄仄平（对仗）。仄平平仄仄平平。仄仄平平（重叠），仄仄仄平平。仄仄仄平平仄（衬托），仄仄仄平平（与上片对应）。', 2, 65, '黄庭坚见晚情如旧。交疏分已深。舞时歌处动人心。烟水数年魂梦，无处可追寻。昨夜灯前见。重题汉上襟。便愁云雨又难禁。晓也星稀，晓也月西沈。晓也雁行低度，不会寄芳音。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('声声慢', '聲聲慢', '胜胜慢,凤示凰,寒松叹,人在楼上', '声声慢，词牌名。据传蒋捷作此慢词俱用“声”字入韵，故称此名。亦称《胜胜慢》、《凤示凰》、《寒松叹》、《人在楼上》。双调，上片十句，押四平韵，四十九字；下片九句，押四平韵，四十八字，共九十七字,长调。又有仄韵体（一般押入声）。用“仙吕调”。', '平平仄仄，仄仄平平，平平仄仄平平（韵）。仄仄平平，平平仄仄平平（韵）。平平仄仄仄仄，仄平平、仄仄平平（韵）。
仄平仄，仄平平仄仄，仄仄平平（韵）。仄仄平平仄仄，仄平平平平，仄仄平平（韵）。
仄仄平平，仄仄平平平平（韵）。平平仄平仄仄，仄平平、平仄平平（韵）。仄仄仄，平平仄、仄仄平平（韵）。', 2, 49, '**李清照声声慢**

寻寻觅觅，冷冷清清，
凄凄惨惨戚戚。
乍暖还寒时候，最难将息。
三杯两盏淡酒，
怎敌他、晚来风急。
雁过也，正伤心，却是旧时相识。
满地黄花堆积，憔悴损，如今有谁堪摘？
守着窗儿，独自怎生得黑。
梧桐更兼细雨，到黄昏，点点滴滴。
这次第，怎一个愁字了得。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('天仙子', '天仙子', NULL, '天仙子，词牌名。又名〈万斯年〉。原为咏天仙的。因皇甫松词有“懊恼天仙应有以”句，取以为名。唐时为仄韵单调，宋人改用双调。

双调六十八字，前后阕各五[仄]韵，上去通押。第四、第五两句，[平][仄]多不定，但是第二句第二字必用去声。', '仄仄平平平仄仄，仄仄平平平仄仄。平平仄仄仄平平，平平仄，平平仄，仄仄仄平平仄仄。
仄仄平平平仄平，仄仄平平平仄仄。平平仄仄仄平平，平平仄，平平仄，仄仄平平平仄仄。', 2, 68, '**张先**

水调数声持酒听，午醉醒来愁未醒。送春春去几时回？临晚镜，伤流景，往事后期空记省。
沙上并禽池上暝，云破月来花弄影。重重帘幕密遮灯，风不定，人初静，明日落红应满径。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('太常引', '太常引', '太清引', '太常引，词牌名。亦称《太清引》，四十九字，双调，上下阕各三平韵，一韵到底。', '平平仄仄仄平平，仄仄仄平平。仄仄仄平平。仄仄仄、平平仄平。平平仄仄，平平仄仄，仄仄仄平平。仄仄仄平平。仄仄仄、平平仄平。', 2, 49, '**辛弃疾**

一轮秋影转金波。飞镜又重磨。把酒问姮娥，被白发欺人奈何？
乘风好去，长空万里，直下看山河。斫去桂婆娑，人道是清光更多。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('如意令', '如意令', NULL, '《如意令》，词牌名，即双调《如梦令》。其调为双调六十六字，前阕五仄韵，一叠韵，上去通押；后阕同前阕。', '仄仄仄平平仄，仄仄仄平平仄。仄仄仄平平，仄仄仄平平仄。平仄，平仄（叠句），仄仄仄平平仄。仄仄仄平平仄，仄仄仄平平仄。仄仄仄平平，仄仄仄平平仄。平仄，平仄（叠句），仄仄仄平平仄。', 2, 66, '**魏泰**

炎暑尚余八日。火老金柔时节。闻道间生贤。储秀降神崧极。无敌。无敌。当代人偷准的。
射策当为第一。高跃龙门三级。荣看绿袍新。帝渥必加宠锡。良弼。良弼。真个国家柱石。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('如梦令', '如夢令', '忆仙姿,如梦令,宴桃源,不见,比梅,古记,无梦令,如意令', '《如梦令》，词牌名，又名《忆仙姿》、《宴桃源》，单调，三十三字，七句、五仄韵、一叠韵，上去看通押。', '平仄平平平仄，仄仄仄平平仄。平仄仄平平，平仄仄平平仄。平仄，平仄。平仄仄平平仄。', 1, 33, '**李存勖**

曾宴桃源深洞，一曲舞鸾歌凤。长记别伊时，和泪出门相送。如梦，如梦。残月落花烟重。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('定风波', '定風波', NULL, '定风波，词牌名。双调六十二字，前阕三平韵，两仄韵，后阕四仄韵，两平韵。平仄换韵方式为“甲乙甲丙甲丁甲”。以平声韵为主，间以仄声韵。', '仄仄平平仄仄平（韵甲），平平仄仄仄平平（韵甲）。仄仄平平平仄仄（韵乙），平仄（韵乙），平平平仄仄平平（韵甲）。
仄仄平平平仄仄（韵丙），平仄（韵丙），平平仄仄仄平平（韵甲）。仄仄平平平仄仄（韵丁），平仄（韵丁），平平平仄仄平平（韵甲）。', 2, 62, '**苏轼**

三月七日，沙湖道中遇雨。雨具先去，同行皆狼狈，余独不觉，已而遂晴，故作此。
莫听穿林打叶声，何妨吟啸且徐行。竹杖芒鞋轻胜马，谁怕？一蓑烟雨任平生。
料峭春风吹酒醒，微冷，山头斜照却相迎。回首向来萧瑟处，归去，也无风雨也无晴。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('定风波慢', '定風波慢', NULL, '定风波慢，一作定风波令，词牌名。源于唐教坊曲。', '仄平平、仄仄平平，平平仄仄仄仄。仄仄平平，平平仄仄，平仄平平仄。仄平平，仄平仄。平仄平平仄平仄。平仄。仄仄平仄仄，平平平仄。仄平仄仄。仄平平、仄仄平平仄。仄平平仄仄，平平仄仄，平仄平平仄。仄平平，仄平仄。平仄平平仄平仄。
仄仄平平，仄仄仄平仄。仄仄仄、仄仄平平，仄仄仄平，仄仄仄平平仄。仄平平仄仄，平平平平仄仄。仄仄仄、平仄平平，平仄平平仄平仄。平仄。仄仄平平，仄仄平平，仄平仄仄。仄仄仄仄仄，平平仄仄。仄平平仄、仄平平仄。仄平平、仄仄平平，平平仄仄。仄仄平、平仄平仄，仄仄平平仄。', NULL, NULL, '自春来、惨绿愁红，芳心是事可可。日上花梢，莺穿柳带，犹压香衾卧。暖酥消，腻云亸，终日厌厌倦梳裹。无那。恨薄情一去，音书无个。早知恁么。悔当初、不把雕鞍锁。向鸡窗、只与蛮笺象管，拘束教吟课。镇相随，莫抛躲。针线闲拈伴伊坐。和我。免使年少,光阴虚过。——柳永
伫立长堤，澹荡晚风起。骤雨歇、极目萧疏，塞柳万株，掩映箭波千里。走舟车向此，人人奔名竞利。念荡子、终日驱驱，争觉乡关转迢递。何意。绣阁轻抛，锦字难逢，等闲度岁。奈泛泛旅迹，厌厌病绪，近来谙尽，宦游滋味。此情怀、纵写香笺，凭谁与寄。算孟光、争得知我，继日添憔悴。——柳永');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('寿阳曲', '壽陽曲', NULL, '《寿阳曲》，词牌名。一名《落梅风》。', '平平仄，平仄平（韵），仄平平，仄平平仄（韵），平平仄平平仄仄（韵），仄平平，仄平平仄（韵）。', NULL, NULL, '**张可久**

东风景。西子湖。湿冥冥、柳烟花雾。黄莺乱啼蝴蝶舞。几秋千、打将春去。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('小重山', '小重山', '小冲山,小重山令', '小重山，词牌名。亦称《小冲山》、《小重山令》。双调五十八字，前后阕各四平韵，一韵到底。', '平仄平平仄仄平，平平平仄仄、仄平平。仄平平仄仄平平，平平平，平仄仄平平。
平仄仄平平，仄平平仄仄，仄平平。仄平平仄仄平平，平平仄，平仄仄平平。', 2, 58, '**岳飞**

昨夜寒蛩不住鸣，惊回千里梦，已三更，起来独自绕阶行，人悄悄，帘外月胧明。

白首为功名，旧山松竹老，阻归程，欲将心事付瑶琴，知音少，弦断有谁听？');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('御街行', '御街行', NULL, '御街行，词牌名。本调上下阕同，共计七十八字。此一词格亦有变体。', '平平仄仄平平仄，仄仄仄、平平仄。平平仄仄仄平平，仄仄平平平仄。
平平仄仄，平平仄仄，仄仄平平仄。
平平仄仄平平仄，仄仄仄、平平仄。平平仄仄仄平平，仄仄平平平仄。
平平仄仄，平平仄仄，仄仄平平仄。', NULL, 78, '**范仲淹**

纷纷坠叶飘香砌，夜寂静，寒声碎。真珠帘卷玉楼空，天淡银河垂地。
年年今夜，月华如练，长是人千里。
愁肠已断无由醉，酒未到，先成泪。残灯明灭枕头敧，谙尽孤眠滋味。
都来此事，眉间心上，无计相回避。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('忆江南', '憶江南', '谢秋娘,江南好,春去也,望江南,梦江南,梦江口,望江楼,安阳好,梦仙游,步虚声,壶山好,望蓬莱,归塞北', '忆江南，词牌名，初名《谢秋娘》，又名《江南好》、《望江南》、《春去也》、《梦江南》等。

单调，二十七字，五句、三平韵。北宋起开始有双调，实际不过是将单片重复而已。', '平平仄，平仄仄平平。仄仄平平平仄仄，平平平仄仄平平。平仄仄平平。', 2, 27, '**白居易**

江南好，风景旧曾谙。日出江花红胜火，春来江水绿如蓝，能不忆江南？
江南忆，最忆是杭州，山寺月中寻桂子，郡亭枕上看潮头，何日更重游？
江南忆，其次忆吴宫，吴酒一杯春竹叶，吴娃双舞醉芙蓉，早晚复相逢？');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('忆王孙', '憶王孫', '梅苑,独脚令,忆君王,豆叶黄,画蛾眉,栏杆万里心', '忆王孙，词牌名，为北宋词人李重元所创，单调三十一字，五句、五平韵，句句用韵，亦有将单片重复做双调者。另有双调五十四字者，见于《复雅歌词》，又名《怨王孙》，与单调绝不同。', '平平平仄仄平平，仄仄平平平仄平。仄仄平平平仄平。仄平平。仄仄平平平仄平。
平平仄仄仄平平，平仄平平仄仄平。平仄仄平仄仄仄（协韵）。仄平平。平仄平平平仄仄（协韵）。', 2, 31, '**元·白朴**

瑶阶月色晃疏棂。银烛秋光冷画屏。消遣此时此夜景。步闲庭。苔浸凌波罗袜冷。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('忆秦娥', '憶秦娥', '秦楼月,碧云深,双荷叶', '忆秦娥，词牌名。亦称《秦楼月》、《碧云深》、《双荷叶》。相传李白首制此词，因词中有“秦娥梦断秦楼月”句，故名《忆秦娥》。

双调四十六字，前后阕各三仄韵，一叠韵，均须押入声字，一韵到底。', '平中（根据宋代词人的创作，前句一般为平平仄）仄，中平中仄平平仄。平平仄（叠上三字）。中平中仄，仄平平仄。中平中仄平平仄，中平中仄平平仄。平平仄（叠上三字）。中平中仄，仄平平仄。', 2, 46, '**李白：《忆秦娥·萧声咽》**

箫声咽，秦娥梦断秦楼月。秦楼月，年年柳色，灞陵伤别。乐游原上清秋节，咸阳古道音尘绝。音尘绝，西风残照，汉家陵阙。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('念奴娇', '念奴嬌', '百字令,酹江月,大江东去,壶中天,湘月', '念奴娇，词牌名，相传是根据唐代一位叫念奴的歌姬取的调名。亦称《百字令》、《酹江月》、《大江东去》、《壶中天》、《湘月》等。目前最早所见的作品，为北宋的沈唐、苏轼所作。双调一百字，前后段各四仄韵，用律十分规整，一韵到底，常用入声韵。上下阕后七句字数平仄相同。', '平平仄仄，仄平平、仄仄平平平仄（或：仄平平仄仄、仄平平仄）。仄仄平平平仄仄，仄仄平平平仄。仄仄平平，平平仄仄，仄仄平平仄。平平平仄，平平平仄平仄。平仄平仄平平（或平平仄仄平平），平平平仄（或仄仄平平），仄仄平平仄。仄仄平平平仄仄，仄仄平平平仄。仄仄平平，平平仄仄，仄仄平平仄。平平平仄，平平平仄平(仄)。', 2, 100, '大江东去，浪淘尽、千古风流人物。故垒西边，人道是、三国周郎赤壁。乱石穿空，惊涛拍岸，卷起千堆雪。江山如画，一时多少豪杰。
遥想公瑾当年，小乔初嫁了，雄姿英发。羽扇纶巾，谈笑间，樯橹灰飞烟灭。故国神游，多情应笑我，早生华发。人生如梦，一尊还酹江月。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('怨王孙', '怨王孫', NULL, '怨王孙，词牌名。', '双调五十四字，仄韵。格律为：（仄）仄（平）平平仄仄，平仄仄、（平）平平仄。（平）平（仄）仄仄平平，仄仄仄、平平仄。', NULL, NULL, NULL);
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('扬州慢', '揚州慢', NULL, '扬州慢，词牌名，为南宋词人姜夔自创。

双调九十八字，其中上片50字，下片48字。', '平仄平平，仄平平仄，仄平仄仄平平。仄平平仄仄，仄仄仄平平。仄平仄、平平仄仄，仄平平仄，平仄平平。仄平平、平仄平平，平仄平平。
仄平仄仄，仄平平、平仄平平。仄仄仄平平，平平仄仄，平仄平平。仄仄仄平平仄，平平仄、仄仄平平。仄平平平仄，平平平仄平平。', 2, 50, '姜夔：扬州慢·淮左名都
淮左名都，竹西佳处，解鞍少驻初程。过春风十里，尽荠麦青青。自胡马窥江去后，废池乔木，犹厌言兵。渐黄昏、清角吹寒，都在空城。
杜郎俊赏，算而今、重到须惊。纵豆蔻词工，青楼梦好，难赋深情。二十四桥仍在，波心荡冷月无声。念桥边红药，年年知为谁生。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('拜星月慢', '拜星月慢', NULL, '拜星月慢，又名拜星月。词牌名，源于唐教坊曲。《宋史·乐志》记载宫调为般涉调，周邦彦《清真集》记载为高平调。一百四字，前片四仄韵，后片六仄韵。', '仄仄平平，平平平仄，仄仄平平仄仄。仄仄平平，仄平平平仄。仄平仄，仄仄、平平仄仄平仄，仄仄平平平仄。仄仄平平，仄平平平仄。仄平平、仄仄平平仄。平平仄、仄仄平平仄。仄仄仄仄平平，仄平平平仄。仄平平、仄仄平平仄。平平仄、仄仄平平仄。仄仄仄、仄仄平平，仄平平仄仄。', NULL, 104, '夜色催更，清尘收露，小曲幽坊月暗。竹槛灯窗，识秋娘庭院。笑相遇，似觉琼枝玉树相倚，暖日明霞光烂。水盼兰情，总平生稀见。画图中、旧识春风面。谁知道、自到瑶台畔，眷恋雨润云温，苦惊风吹散。念荒寒寄宿无人馆，重门闭、败壁秋虫叹。怎奈向、一缕相思，隔溪山不断。——周邦彦');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('捣练子', '搗練子', '捣练子令', '《捣练子》，词牌名，又名《捣练子令》。单调二十七字，五句、三平韵。又一体，双调三十八字，前后阙各五句、三平韵。', '平仄仄，仄平平。仄仄平平仄仄平。平仄仄平平仄仄，仄平平仄仄平平。
平仄仄，仄平平。仄平平仄仄平平。仄平平，仄仄平。
平仄仄，仄平平。平平仄仄仄平平。仄平平，仄仄平。', 2, 27, '**李煜**

深院静，小庭空。断续寒砧断续风。无奈夜长人不寐，数声和月到帘栊。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('摊破浣溪沙', '攤破浣溪沙', '山花子,南唐浣溪沙', '摊破浣溪沙，词牌名。亦称《山花子》、《南唐浣溪沙》。双调四十八字，前阕三平韵，后阕两平韵，一韵到底。后阕开始两句一般要求对仗。', '中仄中平中仄平，中平中仄仄平平。中仄中平平仄仄，仄平平。中仄中平平仄仄，中平中仄仄平平。中仄中平平仄仄，仄平平。', 2, 48, '**李璟**

菡萏香销翠叶残，西风愁起碧波间。还与容光共憔悴，不堪看。
细雨梦回清漏永，小楼吹彻玉笙寒。簌簌泪珠多少恨，倚栏干。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('昭君怨', '昭君怨', '神奇秘谱', '〈龙朔操〉，又名〈昭君怨〉、〈昭君引〉、〈明妃曲〉，古琴曲，以“昭君出塞”为题材，首见于《神奇秘谱》，近代有陈长林及姚丙炎打谱的版本。有时会与〈龙翔操〉混淆。', NULL, NULL, NULL, NULL);
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('昼夜乐', '晝夜樂', NULL, '昼夜乐，词牌名。本调九十八字，前后阕同。', '平平仄仄平平仄，仄平平，仄平仄。平平仄仄平平，仄仄平平平仄。
仄仄平平平仄仄，仄平仄、仄平平仄。平仄仄平平，仄平平平仄。
平平仄仄平平仄，仄平平、仄平仄。平平仄仄平平，仄仄平平平仄。
仄仄平平平仄仄，仄平仄、仄平平仄。平仄仄平平，仄平平平仄。', NULL, 98, NULL);
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('更漏子', '更漏子', NULL, '更漏子，词牌名。双调四十六字，前阕两仄韵、两平韵，后阕三仄韵，两平韵。', '仄平平，平仄仄，仄仄平平平仄。平仄仄，仄平平（换韵），仄平平仄平。平平仄（换韵），平平仄，仄仄平平仄仄。仄仄仄，仄平平（换韵），平平仄仄平。', 2, 46, '**温庭筠**

玉炉香，红烛泪。偏照画堂秋思。眉翠薄，鬓云残。夜长衾枕寒。梧桐树，三更雨。不道离情正苦。一叶叶，一声声。空阶滴到明。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('望海潮', '望海潮', NULL, '望海潮，词牌名。此曲是柳永所创，平韵双调。亦一百零七字，双调，上阙五平韵、下阙六平韵，一韵到底。', '仄平平仄，仄平平仄，平平仄仄平平。平仄仄平，平平仄仄，平平仄仄平平。仄仄仄平平。
仄平平仄仄（上一下四），仄仄平平。仄仄平平，平平仄仄仄平平。
平平仄仄平平。仄平平仄仄（上一下四），仄仄平平。平仄仄平，平平仄仄，平平仄仄平平。
仄仄仄平平。仄平平仄仄（上一下四），仄仄平平。仄仄平平，平平仄仄仄平平。', 2, 107, '**柳永**

东南形胜，三吴都会，钱塘自古繁华。烟柳画桥，风帘翠幕，参差十万人家。云树绕堤沙。
怒涛卷霜雪，天堑无涯。市列珠玑，户盈罗绮，竞豪奢。
重湖叠𪩘清嘉。有三秋桂子，十里荷花。羌管弄晴，菱歌泛夜，嬉嬉钓叟莲娃。千骑拥高牙。
乘醉听箫鼓，吟赏烟霞。异日图将好景，归去凤池夸。');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('朝中措', '朝中措', '江梅曲,芙蓉曲,梅月圆', '朝中措，词牌名。四十八字，前片三平韵，后片两平韵。《宋史·乐志》记载宫调为黄钟宫。', '中平中仄仄平平。中仄仄平平。中仄中平中仄，中平中仄平平。中平中仄，中平中仄，中仄平平。中仄中平中仄，中平中仄平平。', NULL, 48, '平山阑槛倚晴空。山色有无中。手种堂前垂柳，别来几度春风。文章太守，挥毫万字，一饮千钟。行乐直须年少，尊前看取衰翁。——欧阳修
夜深残月过山房。睡觉北窗凉。起绕中庭独步，一天星斗文章。朝来客话，山林钟鼎，那处难忘。君向沙头细问，白鸥知我行藏。——辛弃疾');
INSERT INTO cipai (name, name_tc, aliases, intro, pattern, section_count, char_count, example) VALUES ('柳梢青', '柳梢青', NULL, '柳梢青，词牌名，又名陇头月、玉水明沙、早春怨、云淡秋空、雨洗元宵等。', '中仄平平，中平中仄，中仄平平。中仄平平，中平中仄，中仄平平。
中平中仄平平，中中仄、平平仄平。中仄平平，中平中仄，中仄平平？
平仄平平，仄平仄仄，平仄平平。仄仄平平，平平仄仄，平仄平平。
平平仄仄平平，仄仄仄、平平仄平。仄仄平平，平平仄仄，平仄平平。
仄平中仄，中中中中，中中中仄。中仄中平，中平中仄，中平平仄。
中平中仄平平，中中仄、中平中仄。中仄中平，中平中仄，中平平仄。
平仄平平，仄平仄仄，平平平仄。仄仄平平，仄平平仄，仄平平仄。
平平仄仄平平，平仄仄、平平平仄。仄仄平平，平平仄仄，平平平仄。
平平仄仄，平仄平仄，平平平仄。仄仄平平，仄平仄仄，仄平平仄。
平平仄仄平仄，仄仄仄、平平仄仄。仄仄平平，仄平平仄，平平平仄。
